@app.route("/api/users/<user_id>", methods=["PUT"])
@admin_required
def update_user(user_id):
    user = users_db.get(user_id)
    if not user:
        return jsonify({"message": "User not found"}), 404

    data = request.get_json()
    if not data:
        return jsonify({"message": "Invalid JSON data provided"}), 400

    # Define allowed fields that an admin can update
    allowed_fields = [
        "username",
        "email",
        "role",
        "account_status",
        "subscription_tier",
    ]

    # Define allowed values for specific fields to prevent invalid data
    allowed_roles = ["user", "moderator", "admin"]
    allowed_account_statuses = ["active", "suspended"]
    allowed_subscription_tiers = ["free", "pro", "enterprise"]

    updated_fields = {}
    for field, value in data.items():
        if field in allowed_fields:
            if field == "role" and value not in allowed_roles:
                return jsonify({"message": f"Invalid role: {value}. Allowed roles are {', '.join(allowed_roles)}"}), 400
            if field == "account_status" and value not in allowed_account_statuses:
                return jsonify({"message": f"Invalid account status: {value}. Allowed statuses are {', '.join(allowed_account_statuses)}"}), 400
            if field == "subscription_tier" and value not in allowed_subscription_tiers:
                return jsonify({"message": f"Invalid subscription tier: {value}. Allowed tiers are {', '.join(allowed_subscription_tiers)}"}), 400

            user[field] = value
            updated_fields[field] = value
        else:
            return jsonify({"message": f"Field '{field}' is not allowed for update"}), 400

    if not updated_fields:
        return jsonify({"message": "No valid fields provided for update"}), 400

    # In a real app, you'd save this `user` object back to the database
